import React, { useState, useEffect } from "react";
import { getNextBillNumber, createBill, lookupMenuItem } from "../services/api";

function BillingScreen({ billingDate, userMode }) {
  const [billData, setBillData] = useState({
    table_no: "",
    party_no: "1",
    section: "G",
    clerk_initials: "CLK",
  });
  const [items, setItems] = useState([]);
  const [currentItem, setCurrentItem] = useState({ code: "", quantity: 1 });
  const [billNumber, setBillNumber] = useState(1);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(false);

  useEffect(() => {
    fetchNextBillNumber();
  }, [billingDate]);

  const fetchNextBillNumber = async () => {
    try {
      const response = await getNextBillNumber(billingDate);
      setBillNumber(response.bill_number);
    } catch (err) {
      console.error("Error fetching bill number:", err);
      setError("Failed to fetch bill number");
    }
  };

  const handleAddItem = async () => {
    if (!currentItem.code.trim()) {
      setError("Please enter item code");
      return;
    }

    try {
      setLoading(true);
      const item = await lookupMenuItem(currentItem.code);

      const newItem = {
        code: item.alpha_code || item.numeric_code,
        name: item.name,
        quantity: parseInt(currentItem.quantity),
        unit_price: item.price_general || 0,
      };

      setItems((prev) => [...prev, newItem]);
      setCurrentItem({ code: "", quantity: 1 });
      setError(null);
    } catch (err) {
      console.error("Error adding item:", err);
      setError(`Item "${currentItem.code}" not found`);
    } finally {
      setLoading(false);
    }
  };

  const handleRemoveItem = (index) => {
    setItems((prev) => prev.filter((_, i) => i !== index));
  };

  const calculateTotal = () => {
    const subtotal = items.reduce(
      (sum, item) => sum + item.quantity * item.unit_price,
      0
    );
    const tax = subtotal * 0.05; // 5% tax
    return { subtotal, tax, total: subtotal + tax };
  };

  const handleCreateBill = async () => {
    if (!billData.table_no.trim()) {
      setError("Please enter table number");
      return;
    }

    if (items.length === 0) {
      setError("Please add at least one item");
      return;
    }

    try {
      setLoading(true);

      const billPayload = {
        header: {
          table_no: billData.table_no,
          party_no: billData.party_no,
          section: billData.section,
          clerk_initials: billData.clerk_initials,
          track: "DINE_IN",
        },
        item_codes: items.map((item) => item.code),
        quantities: items.map((item) => item.quantity),
        bill_date: billingDate,
      };

      const response = await createBill(billPayload);

      setSuccess(true);
      setBillData({
        table_no: "",
        party_no: "1",
        section: "G",
        clerk_initials: "CLK",
      });
      setItems([]);
      fetchNextBillNumber();

      setTimeout(() => setSuccess(false), 3000);
    } catch (err) {
      console.error("Error creating bill:", err);
      setError("Failed to create bill");
    } finally {
      setLoading(false);
    }
  };

  const { subtotal, tax, total } = calculateTotal();

  return (
    <div className="billing-screen">
      <div className="billing-header">
        <h2>Billing Screen</h2>
        <div className="bill-info">
          <span>Bill No: {billNumber}</span>
          <span>Date: {billingDate}</span>
          <span>Mode: {userMode}</span>
        </div>
      </div>

      {error && (
        <div className="error-message">
          {error}
          <button onClick={() => setError(null)}>×</button>
        </div>
      )}

      {success && (
        <div className="success-message">Bill created successfully!</div>
      )}

      <div className="billing-content">
        <div className="bill-details">
          <h3>Bill Details</h3>
          <div className="form-row">
            <div className="form-group">
              <label>Table No:</label>
              <input
                type="text"
                value={billData.table_no}
                onChange={(e) =>
                  setBillData((prev) => ({ ...prev, table_no: e.target.value }))
                }
                placeholder="Table number"
              />
            </div>

            <div className="form-group">
              <label>Party No:</label>
              <input
                type="text"
                value={billData.party_no}
                onChange={(e) =>
                  setBillData((prev) => ({ ...prev, party_no: e.target.value }))
                }
                placeholder="Party size"
              />
            </div>

            <div className="form-group">
              <label>Section:</label>
              <select
                value={billData.section}
                onChange={(e) =>
                  setBillData((prev) => ({ ...prev, section: e.target.value }))
                }
              >
                <option value="G">General</option>
                <option value="AC">AC Section</option>
                <option value="P">Private</option>
              </select>
            </div>
          </div>
        </div>

        <div className="item-entry">
          <h3>Add Items</h3>
          <div className="form-row">
            <div className="form-group">
              <label>Item Code:</label>
              <input
                type="text"
                value={currentItem.code}
                onChange={(e) =>
                  setCurrentItem((prev) => ({ ...prev, code: e.target.value }))
                }
                placeholder="Enter item code"
                onKeyPress={(e) => e.key === "Enter" && handleAddItem()}
              />
            </div>

            <div className="form-group">
              <label>Quantity:</label>
              <input
                type="number"
                min="1"
                value={currentItem.quantity}
                onChange={(e) =>
                  setCurrentItem((prev) => ({
                    ...prev,
                    quantity: e.target.value,
                  }))
                }
              />
            </div>

            <div className="form-group">
              <button
                onClick={handleAddItem}
                disabled={loading}
                className="add-item-btn"
              >
                Add Item
              </button>
            </div>
          </div>
        </div>

        <div className="items-list">
          <h3>Bill Items</h3>
          {items.length === 0 ? (
            <p>No items added yet</p>
          ) : (
            <div className="items-table">
              <div className="table-header">
                <span>Code</span>
                <span>Name</span>
                <span>Qty</span>
                <span>Price</span>
                <span>Total</span>
                <span>Action</span>
              </div>

              {items.map((item, index) => (
                <div key={index} className="table-row">
                  <span>{item.code}</span>
                  <span>{item.name}</span>
                  <span>{item.quantity}</span>
                  <span>₹{item.unit_price.toFixed(2)}</span>
                  <span>₹{(item.quantity * item.unit_price).toFixed(2)}</span>
                  <button
                    onClick={() => handleRemoveItem(index)}
                    className="remove-btn"
                  >
                    Remove
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>

        <div className="bill-summary">
          <div className="summary-row">
            <span>Subtotal:</span>
            <span>₹{subtotal.toFixed(2)}</span>
          </div>
          <div className="summary-row">
            <span>Tax (5%):</span>
            <span>₹{tax.toFixed(2)}</span>
          </div>
          <div className="summary-row total">
            <span>Total:</span>
            <span>₹{total.toFixed(2)}</span>
          </div>
        </div>

        <div className="bill-actions">
          <button
            onClick={handleCreateBill}
            disabled={loading || items.length === 0}
            className="create-bill-btn"
          >
            {loading ? "Creating..." : "Create Bill"}
          </button>
        </div>
      </div>
    </div>
  );
}

export default BillingScreen;
